from typing import List

def solve(nums: List[int], k: int) -> int:
    n = len(nums)
    prefixXOR = [0] * (n + 1)
    for i in range(n):
        prefixXOR[i + 1] = prefixXOR[i] ^ nums[i]

    dp = [[0] * (k + 1) for _ in range(n + 1)]

